const regions=[['Punjabi','May include celebrations such as jaggo, choora-related customs or a lively baraat, depending on faith, locality and family.'],['Gujarati','Families may observe events such as garba or sanji, pithi and distinct mandap rituals, with community-specific sequences.'],['Bengali','Recognisable elements can include topor, shubho drishti and saat paak, though observance and interpretation differ.'],['Marathi','Some families include sakhar puda, kelvan, antarpat and laja homa within a concise ceremony structure.'],['Tamil','Tamil Hindu wedding practices differ across communities; oonjal, maalai maatral and tying of the thaali may be included.'],['Telugu','Ceremonies may include jeelakarra bellam, talambralu and other rituals whose sequence varies by community.'],['Kannada','Some Kannada Hindu weddings may include dhare herdu and saptapadi alongside family-specific pre-wedding events.'],['Kerala Hindu','Ceremonies are often concise in some communities and may centre on the thaali, garland exchange and family blessings.'],['Rajasthani','Traditions reflect diverse communities and localities; family customs may shape pre-wedding music, attire and mandap rituals.'],['Sindhi','Some families observe Kachhi Misri, Berana or Saanth alongside wedding-day customs, with considerable variation.'],['Bihari','Rituals may include family-specific forms of tilak, haldi and mandap ceremonies that vary across regions and communities.'],['Odia','Some Odia Hindu weddings include nirbandh, bara jatri and rituals under the mandap, with local and community differences.']];
const regionalBody=`<section class="section">${crumbs([['Regional Weddings']])}${intro('Many regions, countless family stories','Regional Indian Weddings','Short, respectful introductions to traditions across India—designed to help you ask better questions, never to define your family.')}<div class="notice"><strong>Every family is its own source.</strong> Practices vary by locality, language, caste or community, faith tradition and personal choice. Confirm details with your elders and officiant.</div><div class="region-grid">${regions.map(([t,d])=>`<article id="${t.split(' ')[0].toLowerCase()}"><span>${t.slice(0,1)}</span><h2>${t} weddings</h2><p>${d}</p><p class="ask">Ask your family: Which rituals feel essential, and what do they mean to us?</p></article>`).join('')}</div>${ad()}${related([['hindu-wedding-ceremonies.html','Hindu ceremonies','Learn common ritual names and questions to ask.'],['wedding-planning.html','Wedding planning','Organise a multi-event celebration.'],['invitation-wording.html','Invitation wording','Adapt original examples for your family.']])}</section>`;
write('regional-weddings.html',layout({file:'regional-weddings.html',title:'Regional Indian Wedding Traditions | ShaadiGuide',desc:'Explore respectful introductions to Punjabi, Gujarati, Bengali, Marathi, Tamil, Telugu, Kannada, Kerala, Rajasthani, Sindhi, Bihari and Odia weddings.',h1:'Regional Indian Weddings',body:regionalBody,type:'guide',schemas:[breadcrumbSchema('Regional Weddings','regional-weddings.html'),articleSchema('Regional Indian Weddings','Introductions to regional Indian wedding traditions.','regional-weddings.html')]}));

const inviteFaq=[];
const examples=[['Traditional Hindu wedding invitation',`With the blessings of our families and the grace of the Divine,<br><strong>Ananya Sharma</strong> and <strong>Rohan Mehta</strong><br>invite you to share in the joy of their Hindu wedding ceremony<br>on Sunday, 14 February at 10:30 in the morning<br>at The Celebration Hall, Jaipur.<br>Your presence and blessings will make our day complete.`],['Modern Indian wedding invitation',`Two families, one new chapter, and a celebration full of joy.<br>Please join <strong>Mira & Arjun</strong> as they get married<br>on Saturday, 18 September at 5:00 pm.<br>Ceremony, dinner and dancing to follow.`],['Formal invitation',`Mr and Mrs Dev and Leena Kapoor<br>request the pleasure of your company at the wedding of their daughter<br><strong>Ishita</strong> with <strong>Kabir</strong>, son of Mr and Mrs Anand and Reema Malhotra.<br>Kindly join us for the ceremony and reception.`],['Casual invitation',`We are getting married—and it would not feel the same without you!<br>Join us for a day of family, food, laughter and dancing as <strong>Naina & Veer</strong> begin married life together.`],['WhatsApp invitation',`We have wonderful news: we’re getting married! 💛<br>Please join our families on [date] at [venue] to celebrate with us. The invitation card and event details are attached. We would love your blessings and company. Kindly RSVP by [date].`],['Reception-only invitation',`Following their wedding ceremony, <strong>Aditi & Kunal</strong> invite you to an evening reception celebrating their marriage.<br>Please join us for dinner, music and warm wishes on [date] at [venue].`],['No-gifts wording',`Your presence and blessings are the most meaningful gifts we could receive. We respectfully request no boxed gifts.`],['RSVP wording',`Kindly reply by [date] to [name] at [phone/email]. Please mention the names of attending guests and any dietary or accessibility requirements.`],['Wedding postponement wording',`With care for our loved ones, we have decided to postpone our wedding celebration originally planned for [date]. We are grateful for your understanding and will share new arrangements when they are confirmed. Please keep the original date free of travel plans.`],['Thank-you message',`Thank you for celebrating with us and for surrounding our families with such warmth. Your presence, blessings and kind wishes made our wedding deeply meaningful. We are grateful to begin this new chapter with your love.`]];
const inviteBody=`<section class="section">${crumbs([['Invitation Wording']])}${intro('Say it in your own voice','Indian Wedding Invitation Wording','Original wording examples you can adapt for your events, family structure and preferred degree of formality.')} ${article(`<p class="article-lead">A good invitation gives guests warmth and clarity. Replace every sample name, date and detail; check spellings with both families before printing or sending.</p><h2>What every invitation should clarify</h2>${check(['Who is inviting and who is getting married','Event name, date, start time and venue','Whether the invitation covers one event or several','Dress or practical notes only when useful','RSVP contact, deadline and requested guest details'])}<div class="wording-list">${examples.map(([t,d])=>`<section><div><p class="eyebrow">Example</p><h2>${t}</h2></div><blockquote>${d}</blockquote><button class="copy-button" type="button" data-copy>Copy wording</button></section>`).join('')}</div>${ad()}<h2>Before you send</h2><p>Ask one person from each family to proofread names and relationships. Confirm venue spelling, map link, time zone for online guests and whether children or plus-ones are included. For religious titles or Sanskrit wording, check with the person conducting the ceremony.</p>${related([['wedding-planning.html','Wedding planning','Know when invitation decisions fit your timeline.'],['regional-weddings.html','Regional weddings','Consider family language and local customs.'],['contact.html','Contact ShaadiGuide','Share feedback on our wording guides.']])}`)}</section>`;
write('invitation-wording.html',layout({file:'invitation-wording.html',title:'Indian Wedding Invitation Wording Examples | ShaadiGuide',desc:'Original Indian wedding invitation wording for traditional, modern, formal, casual, WhatsApp, reception, RSVP, no-gifts, postponement and thank-you messages.',h1:'Indian Wedding Invitation Wording',body:inviteBody,type:'guide',schemas:[breadcrumbSchema('Invitation Wording','invitation-wording.html'),articleSchema('Indian Wedding Invitation Wording','Original invitation wording examples.','invitation-wording.html')]}));

const budgetFaq=[['How accurate is this wedding budget calculator?','It is a planning estimate based entirely on the numbers you enter. Actual quotations, taxes, service charges, overtime and price changes may differ.'],['What contingency percentage should we use?','Choose a buffer your contributors can comfortably afford. Many planners model several scenarios rather than relying on one percentage; this tool lets you change it freely.'],['Does catering include every event?','Only if your per-guest amount and guest number represent all the catering you intend to include. For different guest counts or menus, calculate each event separately and combine the results under other expenses.'],['Is this financial advice?','No. It is an organisational tool, not financial advice. Make spending decisions based on your own circumstances and seek qualified advice where appropriate.']];
const fields=[['guests','Number of guests','number',250,1],['catering','Catering cost per guest','money',2500,0],['venue','Venue cost','money',500000,0],['decoration','Decoration cost','money',300000,0],['photography','Photography and video','money',200000,0],['clothing','Bridal and groom clothing','money',250000,0],['jewelry','Jewellery budget','money',300000,0],['entertainment','Entertainment','money',120000,0],['invitations','Invitations and stationery','money',40000,0],['transportation','Transportation','money',75000,0],['accommodation','Accommodation','money',200000,0],['gifts','Gifts and favours','money',100000,0],['other','Other expenses','money',50000,0],['contingency','Contingency percentage','percent',10,0]];
const budgetBody=`<section class="section">${crumbs([['Budget Tools'],['Wedding Budget Calculator']])}${intro('Free browser-based tool','Indian Wedding Budget Calculator','Build a clear estimate in Indian rupees, understand the category breakdown and print a summary for your planning conversation.')}<div class="calculator" data-calculator><form class="calculator-form"><div class="calc-head"><h2>Enter your estimates</h2><p>Amounts are in Indian rupees (₹). Use current vendor quotations where possible.</p></div><div class="field-grid">${fields.map(([id,label,type,val,min])=>`<label for="${id}"><span>${label}</span><span class="input-wrap">${type==='money'?'<b>₹</b>':''}<input id="${id}" name="${id}" type="number" min="${min}" step="${type==='percent'?'0.5':'1'}" value="${val}" inputmode="decimal" aria-describedby="${id}-hint">${type==='percent'?'<b>%</b>':''}</span><small id="${id}-hint">${type==='money'?'Enter amount without commas':type==='percent'?'Suggested planning range: 0–30%':'Used for catering and per-guest total'}</small></label>`).join('')}</div><div class="calc-actions"><button class="button" type="submit">Calculate estimate</button><button class="button secondary" type="reset">Reset</button><button class="button text-button" type="button" data-print>Print summary</button></div></form><section class="results" aria-live="polite"><p class="eyebrow">Your working estimate</p><h2><span>Estimated total wedding cost</span><strong data-total>₹0</strong></h2><div class="result-stats"><div><span>Cost per guest</span><b data-per-guest>₹0</b></div><div><span>Contingency amount</span><b data-contingency>₹0</b></div></div><h3>Category breakdown</h3><div class="breakdown" data-breakdown></div><p class="estimate-note">This is an estimate, not a quotation or financial recommendation. Actual costs, taxes and contract terms will vary.</p></section></div>${article(`<h2>How to use your result</h2><ol><li><strong>Start with comparable quotations.</strong> Enter what vendors include, not only the headline price.</li><li><strong>Review the largest categories.</strong> Ask whether they reflect your priorities.</li><li><strong>Save several scenarios.</strong> Try different guest numbers, venue choices or menu rates.</li><li><strong>Agree on a ceiling.</strong> Your estimate should remain below what contributors can comfortably spend.</li></ol><h2>Reduce costs responsibly</h2>${check(['Refine the guest list before committing to per-person costs.','Choose fewer, well-planned events instead of stretching the same budget thinly.','Ask venues what furniture, staffing and power are already included.','Use seasonal, locally available flowers and reusable décor elements.','Prioritise photography hours around the moments you value most.','Send digital invitations where appropriate and print selectively.','Avoid transferring unreasonable risk or last-minute demands to small vendors.'])}${ad()}${faqs(budgetFaq)}`,false)}</section>`;
write('wedding-budget-calculator.html',layout({file:'wedding-budget-calculator.html',title:'Indian Wedding Budget Calculator (Free) | ShaadiGuide',desc:'Estimate your Indian wedding cost in INR, see category totals, contingency and cost per guest, then print a useful browser-based summary.',h1:'Indian Wedding Budget Calculator',body:budgetBody,type:'calculator-page',schemas:[breadcrumbSchema('Wedding Budget Calculator','wedding-budget-calculator.html'),{'@context':'https://schema.org','@type':'WebApplication',name:'Indian Wedding Budget Calculator',url:`${site}/wedding-budget-calculator.html`,applicationCategory:'FinanceApplication',operatingSystem:'Any',isAccessibleForFree:true,description:'A free browser-based Indian wedding cost estimation tool.'},faqSchema(budgetFaq)]}));

const simplePages={
'about.html':{title:'About ShaadiGuide | Our Mission & Standards',desc:'Learn about ShaadiGuide’s mission, readers, editorial standards and respectful approach to regional and family differences.',h1:'Planning guidance with cultural care',label:'About ShaadiGuide',content:`<h2>Our mission</h2><p>ShaadiGuide helps couples and families plan Indian weddings with more clarity and less pressure. We bring practical organisation together with respectful explanations of Hindu wedding culture.</p><h2>Who we serve</h2><p>Our guides are for couples, parents, relatives, friends and guests in India and around the world. We write for people continuing family traditions, adapting them, learning about a partner’s culture or creating a celebration that combines several backgrounds.</p><h2>Our editorial standards</h2><p>We aim for useful, original and clearly structured content. We separate practical suggestions from cultural or religious explanation, avoid presenting one practice as universal and do not invent auspicious dates or claim spiritual authority.</p><h2>Sources and verification</h2><p>We use primary or authoritative sources when a claim can be verified, especially for legal and government procedures. Cultural guides also rely on careful comparison and clearly identify practices that differ; family-specific or religious details should be checked locally.</p><h2>Respect for difference</h2><p>Indian wedding traditions differ by region, language, community, family and individual values. Where religious detail matters, we encourage readers to speak with their priest, pandit, officiant or elders.</p><h2>Updates and corrections</h2><p>We revisit pages when procedures, features or reliable information change. Readers can report a possible error through the <a href="contact.html">contact page</a>; meaningful corrections are made at the source so regenerated pages remain consistent.</p><h2>Practical and original content</h2><p>Our checklists, wording examples and planning tools are created for ShaadiGuide. They are starting points to adapt—not substitutes for personal, legal, financial or religious advice.</p>`},
'contact.html':{title:'Contact ShaadiGuide | Questions & Corrections',desc:'Contact ShaadiGuide with editorial feedback, correction requests or ideas for useful Indian wedding planning resources.',h1:'We would like to hear from you',label:'Contact',content:`<p class="article-lead">Send editorial feedback, suggest a guide or tell us about a correction. The simplest way to reach us is by email.</p><div class="contact-card"><div><h2>Email ShaadiGuide</h2><p><a class="email-link" href="mailto:hello@shaadiguide.in">hello@shaadiguide.in</a></p><p>For a correction, include the page title or URL, the passage in question and, where possible, a reliable source or local context. Please do not email identity documents, financial details or other sensitive personal information.</p><h2>What happens next</h2><p>Feedback is reviewed against the site’s editorial standards. A message does not create a professional-client relationship, and ShaadiGuide cannot provide personalised legal, financial or religious advice.</p></div><div><h2>Contact form preview</h2><form class="static-form"><label>Name<input type="text" disabled placeholder="Your name"></label><label>Email<input type="email" disabled placeholder="you@example.com"></label><label>Message<textarea disabled rows="5" placeholder="Your message"></textarea></label><button class="button" disabled type="button">Form coming later</button></form><p class="form-note">This static form does not send messages. Form handling may be connected in a future phase; please use the email link for now.</p></div></div>`},
'privacy.html':{title:'Privacy Policy | ShaadiGuide',desc:'Read the general privacy policy for ShaadiGuide, a static informational website, including cookies, analytics, advertising and user choices.',h1:'Privacy Policy',label:'Legal',content:`<p class="meta-note">Last updated: 15 July 2026</p><p>ShaadiGuide is currently a static informational website. This policy explains what may be processed when you visit and how we will communicate future changes.</p><h2>Log information</h2><p>Our web host may automatically process standard technical logs such as IP address, browser type, requested page, date and time, and referring page for security and reliable delivery. ShaadiGuide does not currently operate its own user database.</p><h2>Cookies</h2><p>We do not currently set advertising, account or personalisation cookies. Essential hosting infrastructure may use limited technical mechanisms. If we add optional cookies, we will update this notice and provide choices where required.</p><h2>Advertising</h2><p>Pages contain labelled advertising placeholders only. No advertising network is currently installed. If advertising is introduced, partners may process information under their own policies and applicable consent requirements.</p><h2>Analytics</h2><p>ShaadiGuide has not installed an analytics service in this Phase 1 site. If analytics is added, we will describe the provider, purpose and available controls.</p><h2>External links</h2><p>Links to external sites are governed by those sites’ privacy practices. Review them before providing information.</p><h2>Children’s privacy</h2><p>This site is intended for a general audience and does not knowingly collect personal information from children through accounts or forms.</p><h2>Your choices</h2><p>You may control browser settings, decline to email us and leave the site at any time. Contact us to ask about information you have voluntarily sent by email.</p><h2>Contact and updates</h2><p>Questions may be sent to <a href="mailto:hello@shaadiguide.in">hello@shaadiguide.in</a>. We may update this policy when the site’s features or legal requirements change; the date above will show the latest revision.</p>`},
'terms.html':{title:'Terms of Use | ShaadiGuide',desc:'Terms governing informational use of ShaadiGuide, including cultural variation, intellectual property, acceptable use and liability limitations.',h1:'Terms of Use',label:'Legal',content:`<p class="meta-note">Last updated: 15 July 2026</p><h2>Informational use</h2><p>ShaadiGuide provides general educational and planning information. By using the site, you agree to use it lawfully and apply your own judgement.</p><h2>No professional advice</h2><p>Content is not legal, financial, medical, religious or other professional advice. Consult appropriately qualified professionals or your priest, pandit, officiant or elders for advice specific to you.</p><h2>Cultural variation</h2><p>Wedding practices and interpretations vary. An overview cannot represent every region, community or family, and no page should be treated as the only correct form of a tradition.</p><h2>Intellectual property</h2><p>Unless otherwise stated, original text, design and code on ShaadiGuide are protected by applicable intellectual-property law. You may print pages for personal planning but may not republish substantial content as your own.</p><h2>External links</h2><p>External links may be provided for convenience. We do not control or endorse every linked page.</p><h2>Limitation of liability</h2><p>To the extent permitted by law, ShaadiGuide is not liable for losses arising from reliance on general content, calculator estimates, vendor decisions, external websites or temporary site unavailability.</p><h2>Acceptable use</h2><p>Do not interfere with the site, attempt unauthorised access, distribute harmful code, scrape it abusively or use its content unlawfully.</p><h2>Changes</h2><p>We may revise these terms as the site develops. Continued use after an update means the revised terms apply from the displayed update date.</p>`},
'disclaimer.html':{title:'Website Disclaimer | ShaadiGuide',desc:'Important disclaimers about ShaadiGuide’s general information, cultural variation, budget estimates, vendors and external links.',h1:'Disclaimer',label:'Legal',content:`<h2>Educational purpose</h2><p>ShaadiGuide content is provided for general education and wedding planning. Although we aim to be careful and useful, information may be incomplete, become outdated or not fit your circumstances.</p><h2>Cultural and religious variation</h2><p>Indian and Hindu wedding customs vary by region, community, lineage and family. Descriptions are introductions, not religious rulings. Confirm ceremony details with your priest, pandit, officiant or elders.</p><h2>Budget calculator estimates</h2><p>The calculators apply arithmetic to figures entered by the visitor. They do not account for every tax, fee, contract term, price change or personal circumstance. Results are estimates and not quotations or promises of cost.</p><h2>Legal and administrative information</h2><p>Marriage-registration and document-planning pages summarise general questions to verify. Official requirements can differ by law, jurisdiction and authority; always use the linked government service and seek qualified advice when needed.</p><h2>Vendors and purchases</h2><p>Any vendor-related guidance is general. Check credentials, contracts, insurance where relevant, product details, quotations and independent references before committing.</p><h2>No professional advice</h2><p>Nothing on this site is legal, financial, medical, religious or other professional advice.</p><h2>External links</h2><p>We are not responsible for the accuracy, availability, security or policies of external websites. A link does not necessarily imply endorsement; confirm important instructions at their official source.</p>`},
'editorial-policy.html':{title:'Editorial Policy | ShaadiGuide',desc:'How ShaadiGuide creates original content, fact-checks practical guidance, handles cultural sensitivity, corrections, AI assistance and advertising.',h1:'Editorial Policy',label:'Our standards',content:`<h2>Original content standards</h2><p>ShaadiGuide publishes original explanations, checklists, examples and tools. We do not copy another wedding website or present lightly rewritten material as our own.</p><h2>Sources and verification</h2><p>We distinguish verifiable planning information from traditions that vary. Primary and authoritative sources are preferred for law, government services and other procedural claims. Cultural information is framed as common practice rather than a universal rule, and religious specifics should be confirmed with the family’s officiant or elders.</p><h2>Editorial review</h2><p>Pages are checked for internal consistency, clear sourcing where needed, respectful terminology, working links and alignment between visible content and structured data. A review note or date is added only when a meaningful review has actually occurred; it does not imply professional endorsement.</p><h2>Cultural sensitivity</h2><p>We avoid treating North Indian, upper-caste, metropolitan or any other experience as universally Indian. We use respectful language, acknowledge variation and welcome informed correction.</p><h2>Corrections policy</h2><p>Readers may email <a href="mailto:hello@shaadiguide.in">hello@shaadiguide.in</a> with the page, issue and supporting context. Substantive errors are reviewed against reliable sources and corrected at the source template where applicable, so future builds retain the change.</p><h2>AI-assisted content policy</h2><p>AI tools may assist with drafting, structure or quality checks. AI output is not treated as a source. Material is reviewed for accuracy, originality, tone, bias and cultural overgeneralisation before publication.</p><h2>Updating older pages</h2><p>We revisit guides when official procedures, site features or reliable information change. Update dates are used only after a substantive review, not for cosmetic edits.</p><h2>Affiliate and advertising transparency</h2><p>The site contains labelled advertising placeholders but no active advertising or affiliate programme. If commercial relationships are introduced, relevant pages will disclose them clearly and editorial recommendations will remain independently framed.</p>`}
};
